# OEIS sequence: A208448

from math import prod
from collections import Counter
from sympy import factorint
def A208448(n):
    def f(n):
        c, j = Counter(), 1
        while j<=n:
            k = n//j
            a = -j+(j:=n//k+1)
            c += {p:e*a for p, e in factorint(k).items()}
        return c
    x, y = f(n), f(n+1)
    return prod(p**min(x[p],y[p]) for p in x) # _Chai Wah Wu_, May 06 2026

